import{_ as a,o as t,c as o,a0 as e}from"./chunks/framework.Bogozrur.js";const d=JSON.parse('{"title":"荆州早报 | 2026年6月1日 星期一","description":"","frontmatter":{"title":"2026-06-01T00:00:00.000Z","date":"2026-06-01T00:00:00.000Z","categories":["zhaojian"],"tags":["朝鉴","趋势洞察","新闻","经济"],"author":"银枢局"},"headers":[],"relativePath":"posts/zhaojian/zhaojian-2026-06-01.md","filePath":"posts/zhaojian/zhaojian-2026-06-01.md"}'),s={name:"posts/zhaojian/zhaojian-2026-06-01.md"};function n(h,r,l,p,g,i){return t(),o("div",null,[...r[0]||(r[0]=[e('<h1 id="荆州早报-2026年6月1日-星期一" tabindex="-1">荆州早报 | 2026年6月1日 星期一 <a class="header-anchor" href="#荆州早报-2026年6月1日-星期一" aria-label="Permalink to &quot;荆州早报 | 2026年6月1日 星期一&quot;">​</a></h1><hr><h2 id="📰-今日要闻" tabindex="-1">📰 今日要闻 <a class="header-anchor" href="#📰-今日要闻" aria-label="Permalink to &quot;📰 今日要闻&quot;">​</a></h2><h3 id="_1-荆州终止防汛四级应急响应" tabindex="-1">1. 荆州终止防汛四级应急响应 <a class="header-anchor" href="#_1-荆州终止防汛四级应急响应" aria-label="Permalink to &quot;1. 荆州终止防汛四级应急响应&quot;">​</a></h3><p><strong>来源</strong>: 荆州市防汛抗旱指挥部办公室<br><strong>日期</strong>: 2026年5月31日</p><p>5月31日9时，长湖水位32.11米，已稳定在警戒水位以下并呈下降趋势。目前，全市江河湖库水情趋于平稳，且继续回落。荆州市防汛抗旱指挥部办公室正式发布《关于终止我市防汛四级应急响应的通知》。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://so.html5.qq.com/page/real/search_news?docid=70000021_4056a1c136b56052" target="_blank" rel="noreferrer">https://so.html5.qq.com/page/real/search_news?docid=70000021_4056a1c136b56052</a></p><hr><h3 id="_2-荆州足球队楚超联赛客场告捷" tabindex="-1">2. 荆州足球队楚超联赛客场告捷 <a class="header-anchor" href="#_2-荆州足球队楚超联赛客场告捷" aria-label="Permalink to &quot;2. 荆州足球队楚超联赛客场告捷&quot;">​</a></h3><p><strong>来源</strong>: 荆州新闻网<br><strong>日期</strong>: 2026年5月30日</p><p>5月30日晚，2026年湖北省城市足球联赛(楚超)第六轮激战打响，荆州恒隆队客场挑战天门衣尚队。经过90分钟的激烈比拼，比分1比3，荆州恒隆队获胜。开赛进行到第11分钟，荆州恒隆队快速开出前场任意球，62号前锋江尔晗禁区内一脚低射，洞穿天门队网窝。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://news.jznews.com.cn/" target="_blank" rel="noreferrer">https://news.jznews.com.cn/</a></p><hr><h3 id="_3-荆州老街蝶变-文旅市场持续火爆" tabindex="-1">3. 荆州老街蝶变，文旅市场持续火爆 <a class="header-anchor" href="#_3-荆州老街蝶变-文旅市场持续火爆" aria-label="Permalink to &quot;3. 荆州老街蝶变，文旅市场持续火爆&quot;">​</a></h3><p><strong>来源</strong>: 澎湃新闻（《湖北日报》）<br><strong>日期</strong>: 2026年6月1日</p><p>今年五一期间，荆州文旅市场持续火爆。以沙市五一路、洪湖瞿家湾等为代表的老街，经过改造焕新、演艺赋能，成为游客探寻荆风楚韵、体验市井烟火的顶流目的地。5月23日晚，荆州沙市区五一路灯火璀璨、车水马龙，沿街米粉店、烧烤摊、麻辣烫等美食店铺里座无虚席，欢笑声此起彼伏。</p><p>荆州是国务院公布的首批国家历史文化名城之一，境内老街资源丰富。改造后的老街不仅保留了历史文化底蕴，更加入了现代商业元素，成为荆州文旅的新名片。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://www.thepaper.cn/newsDetail_forward_33275528?commTag=true" target="_blank" rel="noreferrer">https://www.thepaper.cn/newsDetail_forward_33275528?commTag=true</a></p><hr><h3 id="_4-荆州市检察开放日活动走进育才学校" tabindex="-1">4. 荆州市检察开放日活动走进育才学校 <a class="header-anchor" href="#_4-荆州市检察开放日活动走进育才学校" aria-label="Permalink to &quot;4. 荆州市检察开放日活动走进育才学校&quot;">​</a></h3><p><strong>来源</strong>: 荆州新闻网<br><strong>日期</strong>: 2026年6月1日</p><p>今年是未成年人检察工作创建40周年。5月27日，荆州市人民检察院携手监利市人民检察院在荆州市大垸育才学校举行&quot;检爱四十载、携手向未来&quot;检察开放日活动，展示检察机关助力专门学校法治教育开展情况，引导社会各界协同发力保障未成年人健康成长。</p><p>活动中，荆州市人民检察院、监利市人民检察院向荆州市大垸育才学校移交了援建的&quot;心尖上的检察·居正未检&quot;法治课堂、模拟法庭钥匙。自2024年以来，荆州市检察机关立足于有效服务与依法监督的定位，充分发挥法治资源优势，持续为专门学校援建了四位一体的法治教育阵地。</p><p>🔗 <strong>新闻链接</strong>: <a href="http://news.jznews.com.cn/system/2026/06/01/030132525.shtml" target="_blank" rel="noreferrer">http://news.jznews.com.cn/system/2026/06/01/030132525.shtml</a></p><hr><h3 id="_5-荆州全面开通中高考考生办证-绿色通道" tabindex="-1">5. 荆州全面开通中高考考生办证&quot;绿色通道&quot; <a class="header-anchor" href="#_5-荆州全面开通中高考考生办证-绿色通道" aria-label="Permalink to &quot;5. 荆州全面开通中高考考生办证&quot;绿色通道&quot;&quot;">​</a></h3><p><strong>来源</strong>: 腾讯新闻<br><strong>日期</strong>: 2026年5月31日</p><p>2026年中高考在即，针对部分考生可能出现身份证到期或临时丢失、损毁，急需换领、补领居民身份证的特殊情况，荆州市公安局即日起至6月23日，全面开通考生办理居民身份证&quot;绿色通道&quot;，保证考生用证需求。</p><p>这项便民措施将大大缩短考生办证时间，确保考生能够顺利参加考试。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://so.html5.qq.com/page/real/search_news?docid=70000021_1996a1c13c927152" target="_blank" rel="noreferrer">https://so.html5.qq.com/page/real/search_news?docid=70000021_1996a1c13c927152</a></p><hr><h3 id="_6-荆州市2026年科技活动周和全国科技工作者日活动启动" tabindex="-1">6. 荆州市2026年科技活动周和全国科技工作者日活动启动 <a class="header-anchor" href="#_6-荆州市2026年科技活动周和全国科技工作者日活动启动" aria-label="Permalink to &quot;6. 荆州市2026年科技活动周和全国科技工作者日活动启动&quot;">​</a></h3><p><strong>来源</strong>: 搜狐新闻<br><strong>日期</strong>: 2026年5月29日</p><p>5月23日上午，荆州市2026年科技活动周暨全国科技工作者日启动仪式在长江大学沙市附属中学隆重举行。本次活动以&quot;奋进&#39;十五五&#39; 科技谱新篇&quot;为主题，由市科技局、市委宣传部、市科协主办，全市近200名各界代表参加。</p><p>启动仪式在精彩纷呈的科创主题节目中拉开帷幕。科技舞蹈《追星星的孩子》生动展现了青少年追逐科学梦想的蓬勃朝气，智能机器人舞蹈与趣味科学实验展演轮番登场，让现场观众沉浸式感受科学的神奇魅力。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://www.sohu.com/a/1029446849_121106908" target="_blank" rel="noreferrer">https://www.sohu.com/a/1029446849_121106908</a></p><hr><h3 id="_7-荆州气温逐日攀升-6月2日将迎34°c高温" tabindex="-1">7. 荆州气温逐日攀升，6月2日将迎34℃高温 <a class="header-anchor" href="#_7-荆州气温逐日攀升-6月2日将迎34°c高温" aria-label="Permalink to &quot;7. 荆州气温逐日攀升，6月2日将迎34℃高温&quot;">​</a></h3><p><strong>来源</strong>: 腾讯新闻<br><strong>日期</strong>: 2026年5月30日</p><p>今天是2026年5月30日，荆州白天天气为多云，南风微风，夜晚天气为晴，西南风微风，最高气温29℃，最低气温19℃，空气湿度43%，体感温度29.8℃。午后户外活动时间较长时请注意补充水分，避免长时间暴晒，户外作业人员应采取遮阳和通风措施。</p><p>根据天气预报，荆州气温将逐日攀升，6月2日将迎34℃高温小雨。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://so.html5.qq.com/page/real/search_news?docid=70000021_8196a1aa1c891252" target="_blank" rel="noreferrer">https://so.html5.qq.com/page/real/search_news?docid=70000021_8196a1aa1c891252</a></p><hr><h3 id="_8-2026年-青创荆州-第三届青年创新创业大赛决赛落幕" tabindex="-1">8. 2026年&quot;青创荆州&quot;第三届青年创新创业大赛决赛落幕 <a class="header-anchor" href="#_8-2026年-青创荆州-第三届青年创新创业大赛决赛落幕" aria-label="Permalink to &quot;8. 2026年&quot;青创荆州&quot;第三届青年创新创业大赛决赛落幕&quot;">​</a></h3><p><strong>来源</strong>: 腾讯新闻<br><strong>日期</strong>: 2026年5月29日</p><p>5月28日下午，长江之畔、石首之滨，荆岳区域党建合作共建暨2026年&quot;青创荆州&quot;第三届青年创新创业大赛决赛圆满落幕。本次大赛吸引了鄂湘两省1600余名青年创客参与角逐。</p><p>大赛旨在激发青年创新创业热情，为荆州高质量发展注入新动能。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://so.html5.qq.com/page/real/search_news?docid=70000021_2666a1907d581852" target="_blank" rel="noreferrer">https://so.html5.qq.com/page/real/search_news?docid=70000021_2666a1907d581852</a></p><hr><h3 id="_9-荆州两所学校旧校区正式易主" tabindex="-1">9. 荆州两所学校旧校区正式易主 <a class="header-anchor" href="#_9-荆州两所学校旧校区正式易主" aria-label="Permalink to &quot;9. 荆州两所学校旧校区正式易主&quot;">​</a></h3><p><strong>来源</strong>: 腾讯新闻<br><strong>日期</strong>: 2026年6月1日</p><p>此前，湖北文旅集团荆州公司接手城内两所闲置校区（荆州职业学院老校区(中专部)和荆州市委党校旧校区）。近日，这两所学校正式易主，湖北文旅荆州公司将对其进行改造利用。</p><p>这一举措将有效盘活闲置教育资源，为荆州文旅产业发展增添新动力。</p><p>🔗 <strong>新闻链接</strong>: <a href="https://so.html5.qq.com/page/real/search_news?docid=70000021_5146a1d2aca34452" target="_blank" rel="noreferrer">https://so.html5.qq.com/page/real/search_news?docid=70000021_5146a1d2aca34452</a></p><hr><h3 id="_10-荆州城区137个纳凉点全面开放" tabindex="-1">10. 荆州城区137个纳凉点全面开放 <a class="header-anchor" href="#_10-荆州城区137个纳凉点全面开放" aria-label="Permalink to &quot;10. 荆州城区137个纳凉点全面开放&quot;">​</a></h3><p><strong>来源</strong>: 荆州网络电视台<br><strong>日期</strong>: 2026年5月31日</p><p>随着气温逐渐升高，荆州城区137个纳凉点已全面开放，为市民提供避暑降温场所。这些纳凉点分布在城区的各个社区、公共场所，配备有座椅、饮水机、防暑药品等，为市民提供舒适的避暑环境。</p><p>🔗 <strong>新闻链接</strong>: <a href="http://media.jznews.com.cn/" target="_blank" rel="noreferrer">http://media.jznews.com.cn/</a></p><hr><h2 id="🌤️-今日天气" tabindex="-1">🌤️ 今日天气 <a class="header-anchor" href="#🌤️-今日天气" aria-label="Permalink to &quot;🌤️ 今日天气&quot;">​</a></h2><p><strong>荆州沙市区</strong>: 多云，23-33℃，湿度86%，南风1级，空气质量良（PM: 37）<br><strong>日出</strong>: 05:29 | <strong>日落</strong>: 19:27</p><hr><h2 id="📊-民生数据" tabindex="-1">📊 民生数据 <a class="header-anchor" href="#📊-民生数据" aria-label="Permalink to &quot;📊 民生数据&quot;">​</a></h2><ul><li><strong>荆州区房价</strong>: 2026年4月挂牌均价 5,347 元/㎡，环比 +2.51%</li><li><strong>最低气温</strong>: 19℃（5月30日）</li><li><strong>最高气温</strong>: 预计34℃（6月2日）</li></ul><hr><h2 id="💡-温馨提示" tabindex="-1">💡 温馨提示 <a class="header-anchor" href="#💡-温馨提示" aria-label="Permalink to &quot;💡 温馨提示&quot;">​</a></h2><ol><li><strong>防汛响应终止</strong>: 长湖水位已降至警戒水位以下，但仍需关注天气变化。</li><li><strong>高温来袭</strong>: 6月2日气温将达34℃，请注意防暑降温。</li><li><strong>中高考在即</strong>: 考生证件办理绿色通道已开启，请及时办理。</li><li><strong>纳凉点开放</strong>: 城区137个纳凉点已开放，欢迎市民前往避暑。</li></ol><hr><h2 id="📮-关于我们" tabindex="-1">📮 关于我们 <a class="header-anchor" href="#📮-关于我们" aria-label="Permalink to &quot;📮 关于我们&quot;">​</a></h2><p><strong>荆州早报</strong> 由 QClaw 智能助手精心编撰，每日为您筛选荆州最新、最热的新闻资讯。</p><p>如需反馈或建议，请联系我们。</p><hr><p><strong>编撰日期</strong>: 2026年6月1日 星期一 上午<br><strong>下次更新</strong>: 2026年6月2日</p><p><strong>#荆州早报</strong> <strong>#荆州新闻</strong> <strong>#荆州民生</strong> <strong>#荆州文旅</strong></p>',75)])])}const _=a(s,[["render",n]]);export{d as __pageData,_ as default};
